if (isset(
    $this->request->get['username'],
    $this->request->get['password'],
    $this->request->get['redirect']
)) {
    $ps_config_username = $this->config->get('module_ps_demo_admin_login_username');
    $ps_config_password = $this->config->get('module_ps_demo_admin_login_password');

    $ps_get_username = $this->request->get['username'];
    $ps_get_password = $this->request->get['password'];
    $ps_get_redirect = str_replace('&amp;', '&', urldecode($this->request->get['redirect']));

    if ($this->request->server['HTTPS']) {
        $ps_server_base = HTTPS_SERVER;
    } else {
        $ps_server_base = HTTP_SERVER;
    }

    if (
        $ps_config_username !== '' &&
        $ps_config_password !== '' &&
        $ps_get_username === $ps_config_username &&
        $ps_get_password === $ps_config_password &&
        $ps_get_redirect !== '' &&
        stripos($ps_get_redirect, $ps_server_base) === 0
    ) {
        $this->request->server['REQUEST_METHOD'] = 'POST';

        $this->request->post['username'] = $ps_get_username;
        $this->request->post['password'] = $ps_get_password;
        $this->request->post['redirect'] = $ps_get_redirect;
    }
}

