ion/theme/default', 'extension/total/coupon', 'extension/total/credit', 'extension/total/handling', 'extension/total/klarna_fee', 'extension/total/low_order_fee', 'extension/total/reward', 'extension/total/shipping', 'extension/total/sub_total', 'extension/total/tax', 'extension/total/total', 'extension/total/voucher');

if (
    $this->config->get('module_ps_demo_admin_login_status')
    && isset($this->request->get['route'])
    && !in_array($this->request->get['route'], $ps_extension_list)
) {
    $this->load->language('extension/module/ps_demo_admin_login', 'ps_demo_admin_login');

    $ps_language = $this->language->get('ps_demo_admin_login');

    $data['ps_button_copy_url'] = $ps_language->get('button_copy_url');
    $data['ps_text_url_copied'] = $ps_language->get('text_url_copied');

    if (
        strpos($route, '/analytics') !== 0 ||
        strpos($route, '/advertise') !== 0 ||
        strpos($route, '/theme') !== 0
    ) {
        $ps_extension_params = '&store_id=' . $this->request->get['store_id'];
    } else if (strpos($route, '/module') !== 0) {
        $ps_extension_params = '&module_id=' . $this->request->get['module_id'];
    } else {
        $ps_extension_params = '';
    }

    $ps_extension_url = $this->url->link($this->request->get['route'], $ps_extension_params);

    $data['ps_demo_url'] = $this->url->link(
        'common/login',
        'username=' . $this->config->get('module_ps_demo_admin_login_username') .
        '&password=' . $this->config->get('module_ps_demo_admin_login_password') .
        '&redirect=' . urlencode($ps_extension_url),
        true
    );
} else {
    $data['ps_demo_url'] = '';
}

{% if ps_demo_url %}<button type="button" data-demo-url="{{ ps_demo_url }}" data-toggle="tooltip" title="{{ ps_button_copy_url }}" class="btn btn-info btn-copy-demo-url"><i class="fa fa-share-alt"></i></button>
<script>
    function copyToClipboardLegacy(text) {
        var $temp = $('<textarea>');
        $('body').append($temp);
        $temp.val(text).select();
        document.execCommand('copy');
        $temp.remove();
    }

    function showCopyMessage() {
        $('.ps-alert-success').remove();

        $('#content > .container-fluid').prepend('<div class="alert alert-success alert-dismissible ps-alert-success"><i class="fa fa-check-circle"></i> {{ ps_text_url_copied }} <button type="button" class="close" data-dismiss="alert">&times;</button></div>');
    }

    $(document).ready(function() {
        $('.btn-copy-demo-url').on('click', function () {
            var copyText = $(this).attr('data-demo-url');

            if (copyText && copyText.length) {
                if (navigator.clipboard && navigator.clipboard.writeText) {
                    navigator.clipboard.writeText(copyText).then(function() { showCopyMessage(); // Try using the modern Clipboard API first
                    }).catch(function(err) { copyToClipboardLegacy(copyText); showCopyMessage(); });
                } else { // Clipboard API not available, use legacy method
                    copyToClipboardLegacy(copyText);
                    showCopyMessage();
                }
            }
        });
    });
</script>{% endif %}

